+    #[test]
+    fn trigger_with_empty_strings() {
+        let trigger = EscalationTrigger::new(
+            "",
+            TriggerCategory::Regression,
+            TriggerSeverity::Info,
+            "",
+            "",
+            SecurityEpoch::from_raw(0),
+        );
+        // Should still produce a valid hash even with empty strings.
